-- Structure de la table 't_backup_history'
DROP TABLE IF EXISTS `t_backup_history`;
CREATE TABLE `t_backup_history` (
  `id` int NOT NULL AUTO_INCREMENT,
  `filename` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `backup_type` enum('full','incremental','differential') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'full',
  `file_size` bigint DEFAULT '0',
  `compressed_size` bigint DEFAULT '0',
  `tables_count` int DEFAULT '0',
  `views_count` int DEFAULT '0',
  `total_rows` bigint DEFAULT '0',
  `status` enum('success','failed','running') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'running',
  `duration` decimal(10,3) DEFAULT '0.000',
