-- Structure de la table 't_backup_schedule'
DROP TABLE IF EXISTS `t_backup_schedule`;
CREATE TABLE `t_backup_schedule` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `frequency` enum('daily','weekly','monthly','custom') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `time` time NOT NULL DEFAULT '02:00:00',
  `day_of_week` tinyint DEFAULT NULL COMMENT '0=dimanche, 1=lundi, etc.',
  `day_of_month` tinyint DEFAULT NULL COMMENT '1-31',
  `custom_cron` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `backup_type` enum('full','incremental','differential') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'full',
  `is_active` tinyint(1) DEFAULT '1',
  `keep_backups` int DEFAULT '30' COMMENT 'Nombre de sauvegardes à conserver',
  `email_notifications` tinyint(1) DEFAULT '0',
  `email_recipients` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Emails séparés par des virgules',
  `cloud_sync` tinyint(1) DEFAULT '0',
  `cloud_provider` enum('google_drive','dropbox','aws_s3','azure') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `cloud_config` json DEFAULT NULL,
  `last_run` timestamp NULL DEFAULT NULL,
  `next_run` timestamp NULL DEFAULT NULL,
  `run_count` int DEFAULT '0',
  `success_count` int DEFAULT '0',
  `failure_count` int DEFAULT '0',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_active` (`is_active`),
  KEY `idx_next_run` (`next_run`),
  KEY `idx_frequency` (`frequency`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

