-- Structure de la table 't_cote'
DROP TABLE IF EXISTS `t_cote`;
CREATE TABLE `t_cote` (
  `id_note` int NOT NULL AUTO_INCREMENT,
  `matricule` varchar(25) NOT NULL,
  `username` varchar(25) NOT NULL,
  `id_ec` int DEFAULT NULL,
  `id_annee` int NOT NULL,
  `id_mention` int NOT NULL,
  `id_promotion` int NOT NULL,
  `cote_s1` decimal(5,2) NOT NULL DEFAULT '0.00',
  `cote_s2` decimal(5,2) NOT NULL DEFAULT '0.00',
  `id_ue` int DEFAULT NULL,
  `cote_rattrapage_s1` decimal(5,2) DEFAULT NULL COMMENT 'Cote de rattrapage semestre 1',
  `cote_rattrapage_s2` decimal(5,2) DEFAULT NULL COMMENT 'Cote de rattrapage semestre 2',
  `date_rattrapage_s1` datetime DEFAULT NULL COMMENT 'Date de passage du rattrapage S1',
  `date_rattrapage_s2` datetime DEFAULT NULL COMMENT 'Date de passage du rattrapage S2',
  `is_rattrapage_s1` tinyint(1) DEFAULT '0' COMMENT 'Indique si étudiant a passé rattrapage S1',
  `is_rattrapage_s2` tinyint(1) DEFAULT '0' COMMENT 'Indique si étudiant a passé rattrapage S2',
  PRIMARY KEY (`id_note`),
  KEY `fk_cote_etudiant` (`matricule`),
  KEY `fk_cote_utilisateur` (`username`),
  KEY `fk_cote_ec` (`id_ec`),
  KEY `fk_cote_annee` (`id_annee`),
  KEY `fk_cote_mention` (`id_mention`),
  KEY `fk_cote_promotion` (`id_promotion`),
  KEY `fk_cote_ue` (`id_ue`),
  KEY `idx_rattrapage_s1` (`is_rattrapage_s1`),
  KEY `idx_rattrapage_s2` (`is_rattrapage_s2`),
  CONSTRAINT `fk_cote_ue` FOREIGN KEY (`id_ue`) REFERENCES `t_unite_enseignement` (`id_ue`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=27460 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

