CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_unites_enseignements` AS select `ue`.`code_ue` AS `code_ue`,`ue`.`libelle` AS `ue_libelle`,`ue`.`credits` AS `ue_credits`,`ue`.`heures_th` AS `ue_heures_th`,`ue`.`heures_td` AS `ue_heures_td`,`ue`.`heures_tp` AS `ue_heures_tp`,`ue`.`id_semestre` AS `id_semestre`,`ue`.`code_promotion` AS `code_promotion`,`ec`.`id_ec` AS `id_ec`,`ec`.`code_ec` AS `code_ec`,`ec`.`libelle` AS `ec_libelle`,`ec`.`heures_th` AS `ec_heures_th`,`ec`.`heures_td` AS `ec_heures_td`,`ec`.`heures_tp` AS `ec_heures_tp`,`ec`.`coefficient` AS `coefficient`,`ec`.`total_heures` AS `ec_total_heures`,`mu`.`id_mention` AS `id_mention`,`mu`.`id_ue` AS `id_ue`,`mu`.`semestre` AS `semestre` from ((`t_unite_enseignement` `ue` join `t_mention_ue` `mu` on((`mu`.`id_ue` = `ue`.`id_ue`))) left join `t_element_constitutif` `ec` on((`ue`.`id_ue` = `ec`.`id_ue`)));

-- Structure de la table 'vue_credits_coeffs'
DROP TABLE IF EXISTS `vue_credits_coeffs`;
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vue_credits_coeffs` AS select `ue`.`code_ue` AS `code_ue`,`ue`.`libelle` AS `libelle_ue`,`ue`.`credits` AS `credit_ue`,`ec`.`code_ec` AS `code_ec`,`ec`.`libelle` AS `libelle_ec`,`ec`.`coefficient` AS `coef_ec` from (`t_unite_enseignement` `ue` left join `t_element_constitutif` `ec` on((`ec`.`id_ue` = `ue`.`id_ue`)));

-- Structure de la table 'vue_etudiant_inscription'
DROP TABLE IF EXISTS `vue_etudiant_inscription`;
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vue_etudiant_inscription` AS select `e`.`matricule` AS `matricule`,`e`.`nom_etu` AS `nom_etudiant`,`e`.`prenom_etu` AS `prenom_etudiant`,`d`.`id_domaine` AS `id_domaine`,`d`.`nom_domaine` AS `nom_domaine`,`d`.`code_domaine` AS `code_domaine`,`f`.`idFiliere` AS `id_filiere`,`f`.`nomFiliere` AS `nom_filiere`,`f`.`code_filiere` AS `code_filiere`,`m`.`id_mention` AS `id_mention`,`m`.`libelle` AS `nom_mention`,`m`.`code_mention` AS `code_mention`,`p`.`code_promotion` AS `code_promotion`,`p`.`nom_promotion` AS `nom_promotion`,`i`.`date_inscription` AS `date_inscription` from ((((((`t_etudiant` `e` join `t_inscription` `i` on((`e`.`matricule` = `i`.`matricule`))) join `t_mention` `m` on((`i`.`id_mention` = `m`.`id_mention`))) join `t_filiere` `f` on((`m`.`idFiliere` = `f`.`idFiliere`))) join `t_domaine` `d` on((`f`.`id_domaine` = `d`.`id_domaine`))) join `t_promotion` `p` on((`i`.`code_promotion` = `p`.`code_promotion`))) join `t_anne_academique` `aa` on((`i`.`id_annee` = `aa`.`id_annee`)));

-- Structure de la table 'vue_etudiants_domaines'
DROP TABLE IF EXISTS `vue_etudiants_domaines`;
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vue_etudiants_domaines` AS select `e`.`matricule` AS `matricule`,`e`.`nom_etu` AS `nom_etu`,`e`.`prenom_etu` AS `prenom_etu`,`d`.`id_domaine` AS `id_domaine`,`d`.`nom_domaine` AS `nom_domaine`,`d`.`code_domaine` AS `code_domaine` from ((((`t_etudiant` `e` join `t_inscription` `i` on((`e`.`matricule` = `i`.`matricule`))) join `t_mention` `m` on((`i`.`id_mention` = `m`.`id_mention`))) join `t_filiere` `f` on((`m`.`idFiliere` = `f`.`idFiliere`))) join `t_domaine` `d` on((`f`.`id_domaine` = `d`.`id_domaine`))) where ((`e`.`matricule` is not null) and (`d`.`id_domaine` is not null)) group by `e`.`matricule`,`e`.`nom_etu`,`e`.`prenom_etu`,`d`.`id_domaine`,`d`.`nom_domaine`,`d`.`code_domaine`;

-- Structure de la table 'vue_etudiants_mention_promotion'
DROP TABLE IF EXISTS `vue_etudiants_mention_promotion`;
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vue_etudiants_mention_promotion` AS select `e`.`id_etudiant` AS `id_etudiant`,`e`.`matricule` AS `matricule`,`e`.`nom_etu` AS `nom_etu`,`e`.`postnom_etu` AS `postnom_etu`,`e`.`prenom_etu` AS `prenom_etu`,`e`.`sexe` AS `sexe`,`e`.`date_naiss` AS `date_naiss`,`e`.`lieu_naiss` AS `lieu_naiss`,`e`.`nationalite` AS `nationalite`,`e`.`telephone` AS `telephone`,`e`.`email` AS `email`,`i`.`id_mention` AS `id_mention`,`i`.`code_promotion` AS `code_promotion`,`i`.`statut` AS `statut` from (`t_etudiant` `e` join `t_inscription` `i` on((`e`.`matricule` = `i`.`matricule`))) where (`i`.`statut` = 'Actif');

-- Structure de la table 'vue_grille_deliberation'
DROP TABLE IF EXISTS `vue_grille_deliberation`;
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vue_grille_deliberation` AS select `e`.`matricule` AS `matricule`,concat(`e`.`nom_etu`,' ',`e`.`postnom_etu`,' ',`e`.`prenom_etu`) AS `nom_complet`,`i`.`code_promotion` AS `code_promotion`,`i`.`id_mention` AS `id_mention`,`i`.`id_annee` AS `id_annee`,`ue`.`id_semestre` AS `id_semestre`,`mue`.`semestre` AS `semestre_mention`,`ue`.`id_ue` AS `id_ue`,`ue`.`code_ue` AS `code_ue`,`ue`.`libelle` AS `libelle_ue`,`ue`.`credits` AS `credits`,(case when (`ec`.`id_ec` is not null) then `ec`.`id_ec` else concat('UE_',`ue`.`id_ue`) end) AS `id_ec`,(case when (`ec`.`code_ec` is not null) then `ec`.`code_ec` else `ue`.`code_ue` end) AS `code_ec`,(case when (`ec`.`libelle` is not null) then `ec`.`libelle` else `ue`.`libelle` end) AS `libelle_ec`,(case when (`ec`.`coefficient` is not null) then `ec`.`coefficient` else `ue`.`credits` end) AS `coef_ec`,coalesce(`cotes`.`cote_s1`,0.00) AS `cote_s1`,coalesce(`cotes`.`cote_s2`,0.00) AS `cote_s2`,`cotes`.`cote_rattrapage_s1` AS `cote_rattrapage_s1`,`cotes`.`cote_rattrapage_s2` AS `cote_rattrapage_s2`,`cotes`.`date_rattrapage_s1` AS `date_rattrapage_s1`,`cotes`.`date_rattrapage_s2` AS `date_rattrapage_s2`,(case when ((`cotes`.`cote_rattrapage_s1` is not null) and (`cotes`.`cote_rattrapage_s1` > coalesce(`cotes`.`cote_s1`,0))) then `cotes`.`cote_rattrapage_s1` else coalesce(`cotes`.`cote_s1`,0.00) end) AS `meilleure_cote_s1`,(case when ((`cotes`.`cote_rattrapage_s2` is not null) and (`cotes`.`cote_rattrapage_s2` > coalesce(`cotes`.`cote_s2`,0))) then `cotes`.`cote_rattrapage_s2` else coalesce(`cotes`.`cote_s2`,0.00) end) AS `meilleure_cote_s2`,(case when ((coalesce(`cotes`.`cote_s1`,0) > 0) and (coalesce(`cotes`.`cote_s2`,0) > 0)) then round((((case when ((`cotes`.`cote_rattrapage_s1` is not null) and (`cotes`.`cote_rattrapage_s1` > `cotes`.`cote_s1`)) then `cotes`.`cote_rattrapage_s1` else coalesce(`cotes`.`cote_s1`,0) end) + (case when ((`cotes`.`cote_rattrapage_s2` is not null) and (`cotes`.`cote_rattrapage_s2` > `cotes`.`cote_s2`)) then `cotes`.`cote_rattrapage_s2` else coalesce(`cotes`.`cote_s2`,0) end)) / 2),2) when ((coalesce(`cotes`.`cote_s1`,0) > 0) and (coalesce(`cotes`.`cote_s2`,0) = 0)) then (case when ((`cotes`.`cote_rattrapage_s1` is not null) and (`cotes`.`cote_rattrapage_s1` > `cotes`.`cote_s1`)) then `cotes`.`cote_rattrapage_s1` else coalesce(`cotes`.`cote_s1`,0) end) when ((coalesce(`cotes`.`cote_s1`,0) = 0) and (coalesce(`cotes`.`cote_s2`,0) > 0)) then (case when ((`cotes`.`cote_rattrapage_s2` is not null) and (`cotes`.`cote_rattrapage_s2` > `cotes`.`cote_s2`)) then `cotes`.`cote_rattrapage_s2` else coalesce(`cotes`.`cote_s2`,0) end) else 0.00 end) AS `moyenne_ec`,(case when ((`cotes`.`cote_rattrapage_s1` is not null) and (`cotes`.`cote_rattrapage_s1` > coalesce(`cotes`.`cote_s1`,0))) then 1 else 0 end) AS `utilise_rattrapage_s1`,(case when ((`cotes`.`cote_rattrapage_s2` is not null) and (`cotes`.`cote_rattrapage_s2` > coalesce(`cotes`.`cote_s2`,0))) then 1 else 0 end) AS `utilise_rattrapage_s2` from ((((((`t_etudiant` `e` join `t_inscription` `i` on(((`i`.`matricule` = `e`.`matricule`) and (`i`.`statut` = 'Actif')))) join `t_mention_ue` `mue` on((`mue`.`id_mention` = `i`.`id_mention`))) join `t_unite_enseignement` `ue` on(((`ue`.`id_ue` = `mue`.`id_ue`) and (`ue`.`code_promotion` = `i`.`code_promotion`)))) left join `t_element_constitutif` `ec` on((`ec`.`id_ue` = `ue`.`id_ue`))) left join `t_mention_ue_ec` `muec` on(((`muec`.`id_mention_ue` = `mue`.`id_mention_ue`) and (`muec`.`id_ec` = `ec`.`id_ec`)))) left join (select `c1`.`matricule` AS `matricule`,`c1`.`id_ec` AS `id_ec`,`c1`.`id_ue` AS `id_ue`,`c1`.`id_annee` AS `id_annee`,`c1`.`id_mention` AS `id_mention`,`c1`.`cote_s1` AS `cote_s1`,`c1`.`cote_s2` AS `cote_s2`,`c1`.`cote_rattrapage_s1` AS `cote_rattrapage_s1`,`c1`.`cote_rattrapage_s2` AS `cote_rattrapage_s2`,`c1`.`date_rattrapage_s1` AS `date_rattrapage_s1`,`c1`.`date_rattrapage_s2` AS `date_rattrapage_s2` from (`t_cote` `c1` join (select `t_cote`.`matricule` AS `matricule`,coalesce(`t_cote`.`id_ec`,0) AS `id_ec_key`,coalesce(`t_cote`.`id_ue`,0) AS `id_ue_key`,`t_cote`.`id_annee` AS `id_annee`,`t_cote`.`id_mention` AS `id_mention`,max(`t_cote`.`id_note`) AS `max_id_note` from `t_cote` group by `t_cote`.`matricule`,coalesce(`t_cote`.`id_ec`,0),coalesce(`t_cote`.`id_ue`,0),`t_cote`.`id_annee`,`t_cote`.`id_mention`) `c2` on((`c1`.`id_note` = `c2`.`max_id_note`)))) `cotes` on(((`cotes`.`matricule` = `e`.`matricule`) and (`cotes`.`id_annee` = `i`.`id_annee`) and (`cotes`.`id_mention` = `i`.`id_mention`) and (((`ec`.`id_ec` is not null) and (`cotes`.`id_ec` = `ec`.`id_ec`)) or ((`ec`.`id_ec` is null) and (`cotes`.`id_ue` = `ue`.`id_ue`)) or ((`ec`.`id_ec` is not null) and (`cotes`.`id_ec` is null) and (`cotes`.`id_ue` = `ue`.`id_ue`)))))) where ((`ec`.`id_ec` is null) or (`muec`.`id_ec` is not null) or (`muec`.`id_ec` is null)) order by `e`.`nom_etu`,`e`.`postnom_etu`,`e`.`prenom_etu`,`mue`.`semestre`,`ue`.`code_ue`,coalesce(`ec`.`code_ec`,`ue`.`code_ue`);

-- Structure de la table 'vue_grille_deliberation_avec_rattrapage'
DROP TABLE IF EXISTS `vue_grille_deliberation_avec_rattrapage`;
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vue_grille_deliberation_avec_rattrapage` AS select distinct `et`.`matricule` AS `matricule`,concat(`et`.`nom_etu`,' ',`et`.`postnom_etu`,' ',`et`.`prenom_etu`) AS `nom_complet`,`i`.`code_promotion` AS `code_promotion`,`i`.`id_mention` AS `id_mention`,`i`.`id_annee` AS `id_annee`,`ue`.`id_semestre` AS `id_semestre`,`mue`.`semestre` AS `semestre_mention`,`ue`.`id_ue` AS `id_ue`,`ue`.`code_ue` AS `code_ue`,`ue`.`libelle` AS `libelle_ue`,`ue`.`credits` AS `credits`,(case when (`ec`.`id_ec` is not null) then `ec`.`id_ec` else concat('UE_',`ue`.`id_ue`) end) AS `id_ec`,(case when (`ec`.`code_ec` is not null) then `ec`.`code_ec` else `ue`.`code_ue` end) AS `code_ec`,(case when (`ec`.`libelle` is not null) then `ec`.`libelle` else `ue`.`libelle` end) AS `libelle_ec`,(case when (`ec`.`coefficient` is not null) then `ec`.`coefficient` else `ue`.`credits` end) AS `coef_ec`,coalesce(`c`.`cote_s1`,0) AS `cote_s1`,coalesce(`c`.`cote_s2`,0) AS `cote_s2`,`c`.`cote_rattrapage_s1` AS `cote_rattrapage_s1`,`c`.`cote_rattrapage_s2` AS `cote_rattrapage_s2`,`c`.`date_rattrapage_s1` AS `date_rattrapage_s1`,`c`.`date_rattrapage_s2` AS `date_rattrapage_s2`,(case when ((`c`.`cote_rattrapage_s1` is not null) and (`c`.`cote_rattrapage_s1` > coalesce(`c`.`cote_s1`,0))) then `c`.`cote_rattrapage_s1` else coalesce(`c`.`cote_s1`,0) end) AS `meilleure_cote_s1`,(case when ((`c`.`cote_rattrapage_s2` is not null) and (`c`.`cote_rattrapage_s2` > coalesce(`c`.`cote_s2`,0))) then `c`.`cote_rattrapage_s2` else coalesce(`c`.`cote_s2`,0) end) AS `meilleure_cote_s2`,(case when ((`c`.`cote_s1` is not null) and (`c`.`cote_s1` > 0) and (`c`.`cote_s2` is not null) and (`c`.`cote_s2` > 0)) then round((((case when (`c`.`cote_rattrapage_s1` > `c`.`cote_s1`) then `c`.`cote_rattrapage_s1` else `c`.`cote_s1` end) + (case when (`c`.`cote_rattrapage_s2` > `c`.`cote_s2`) then `c`.`cote_rattrapage_s2` else `c`.`cote_s2` end)) / 2),2) when ((`c`.`cote_s1` is not null) and (`c`.`cote_s1` > 0)) then (case when (`c`.`cote_rattrapage_s1` > `c`.`cote_s1`) then `c`.`cote_rattrapage_s1` else `c`.`cote_s1` end) when ((`c`.`cote_s2` is not null) and (`c`.`cote_s2` > 0)) then (case when (`c`.`cote_rattrapage_s2` > `c`.`cote_s2`) then `c`.`cote_rattrapage_s2` else `c`.`cote_s2` end) else 0 end) AS `moyenne_ec`,(case when ((`c`.`cote_rattrapage_s1` is not null) and (`c`.`cote_rattrapage_s1` > coalesce(`c`.`cote_s1`,0))) then 1 else 0 end) AS `est_rattrapage_s1`,(case when ((`c`.`cote_rattrapage_s2` is not null) and (`c`.`cote_rattrapage_s2` > coalesce(`c`.`cote_s2`,0))) then 1 else 0 end) AS `est_rattrapage_s2`,`c`.`cote_s1` AS `note_normale_s1`,`c`.`cote_s2` AS `note_normale_s2`,`c`.`cote_rattrapage_s1` AS `note_rattrapage_s1`,`c`.`cote_rattrapage_s2` AS `note_rattrapage_s2` from (((((`t_etudiant` `et` join `t_inscription` `i` on((`et`.`matricule` = `i`.`matricule`))) join `t_mention_ue` `mue` on((`i`.`id_mention` = `mue`.`id_mention`))) join `t_unite_enseignement` `ue` on((`mue`.`id_ue` = `ue`.`id_ue`))) left join `t_element_constitutif` `ec` on((`ue`.`id_ue` = `ec`.`id_ue`))) left join `t_cote` `c` on(((`et`.`matricule` = `c`.`matricule`) and (`i`.`id_annee` = `c`.`id_annee`) and (`i`.`id_mention` = `c`.`id_mention`) and (((`ec`.`id_ec` is not null) and (`c`.`id_ec` = `ec`.`id_ec`)) or ((`ec`.`id_ec` is null) and (`c`.`id_ue` = `ue`.`id_ue`)))))) where (`i`.`statut` = 'Actif') order by `et`.`nom_etu`,`et`.`postnom_etu`,`et`.`prenom_etu`,`mue`.`semestre`,`ue`.`code_ue`,coalesce(`ec`.`code_ec`,`ue`.`code_ue`);

-- Structure de la table 'vue_grille_deliberation_old'
DROP TABLE IF EXISTS `vue_grille_deliberation_old`;
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vue_grille_deliberation_old` AS select `vue_grille_deliberation`.`matricule` AS `matricule`,`vue_grille_deliberation`.`nom_complet` AS `nom_complet`,`vue_grille_deliberation`.`code_promotion` AS `code_promotion`,`vue_grille_deliberation`.`id_mention` AS `id_mention`,`vue_grille_deliberation`.`id_annee` AS `id_annee`,`vue_grille_deliberation`.`id_semestre` AS `id_semestre`,`vue_grille_deliberation`.`semestre_mention` AS `semestre_mention`,`vue_grille_deliberation`.`id_ue` AS `id_ue`,`vue_grille_deliberation`.`code_ue` AS `code_ue`,`vue_grille_deliberation`.`libelle_ue` AS `libelle_ue`,`vue_grille_deliberation`.`credits` AS `credits`,`vue_grille_deliberation`.`id_ec` AS `id_ec`,`vue_grille_deliberation`.`code_ec` AS `code_ec`,`vue_grille_deliberation`.`libelle_ec` AS `libelle_ec`,`vue_grille_deliberation`.`coef_ec` AS `coef_ec`,`vue_grille_deliberation`.`cote_s1` AS `cote_s1`,`vue_grille_deliberation`.`cote_s2` AS `cote_s2`,`vue_grille_deliberation`.`cote_rattrapage_s1` AS `cote_rattrapage_s1`,`vue_grille_deliberation`.`cote_rattrapage_s2` AS `cote_rattrapage_s2`,`vue_grille_deliberation`.`date_rattrapage_s1` AS `date_rattrapage_s1`,`vue_grille_deliberation`.`date_rattrapage_s2` AS `date_rattrapage_s2`,`vue_grille_deliberation`.`meilleure_cote_s1` AS `meilleure_cote_s1`,`vue_grille_deliberation`.`meilleure_cote_s2` AS `meilleure_cote_s2`,`vue_grille_deliberation`.`moyenne_ec` AS `moyenne_ec`,`vue_grille_deliberation`.`utilise_rattrapage_s1` AS `utilise_rattrapage_s1`,`vue_grille_deliberation`.`utilise_rattrapage_s2` AS `utilise_rattrapage_s2` from `vue_grille_deliberation`;

-- Structure de la table 'vue_programme_etudiant'
DROP TABLE IF EXISTS `vue_programme_etudiant`;
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vue_programme_etudiant` AS select `e`.`matricule` AS `matricule`,`e`.`nom_etu` AS `nom_etu`,`e`.`postnom_etu` AS `postnom_etu`,`e`.`prenom_etu` AS `prenom_etu`,`m`.`id_mention` AS `id_mention`,`m`.`code_mention` AS `code_mention`,`m`.`libelle` AS `mention`,`f`.`idFiliere` AS `idFiliere`,`f`.`code_filiere` AS `code_filiere`,`f`.`nomFiliere` AS `nomFiliere`,`d`.`id_domaine` AS `id_domaine`,`d`.`code_domaine` AS `code_domaine`,`d`.`nom_domaine` AS `nom_domaine`,`p`.`code_promotion` AS `code_promotion`,`p`.`nom_promotion` AS `nom_promotion`,`a`.`id_annee` AS `id_annee`,`a`.`date_debut` AS `date_debut`,`a`.`date_fin` AS `date_fin`,`s`.`id_semestre` AS `id_semestre`,`s`.`code_semestre` AS `code_semestre`,`s`.`nom_semestre` AS `nom_semestre`,`ue`.`id_ue` AS `id_ue`,`ue`.`code_ue` AS `code_ue`,`ue`.`libelle` AS `unite_enseignement`,`ue`.`credits` AS `credits`,`ue`.`heures_th` AS `ue_heures_th`,`ue`.`heures_td` AS `ue_heures_td`,`ue`.`heures_tp` AS `ue_heures_tp`,`ue`.`total_heures` AS `ue_total_heures`,`ec`.`id_ec` AS `id_ec`,`ec`.`code_ec` AS `code_ec`,`ec`.`libelle` AS `element_constitutif`,`ec`.`coefficient` AS `coefficient`,`ec`.`heures_th` AS `ec_heures_th`,`ec`.`heures_td` AS `ec_heures_td`,`ec`.`heures_tp` AS `ec_heures_tp`,`ec`.`total_heures` AS `ec_total_heures`,coalesce(`c_ec`.`cote_s1`,`c_ue`.`cote_s1`) AS `cote_s1`,coalesce(`c_ec`.`cote_s2`,`c_ue`.`cote_s2`) AS `cote_s2` from (((((((((((((`t_etudiant` `e` join `t_inscription` `i` on((`i`.`matricule` = `e`.`matricule`))) join `t_promotion` `p` on((`p`.`code_promotion` = `i`.`code_promotion`))) join `t_anne_academique` `a` on((`a`.`id_annee` = `i`.`id_annee`))) join `t_mention` `m` on((`m`.`id_mention` = `i`.`id_mention`))) join `t_filiere` `f` on((`f`.`idFiliere` = `m`.`idFiliere`))) join `t_domaine` `d` on((`d`.`id_domaine` = `f`.`id_domaine`))) join `t_unite_enseignement` `ue` on((`ue`.`code_promotion` = `i`.`code_promotion`))) join `t_semestre` `s` on(((`s`.`id_semestre` = `ue`.`id_semestre`) and (`s`.`id_annee` = `a`.`id_annee`)))) join `t_mention_ue` `mu` on(((`mu`.`id_mention` = `m`.`id_mention`) and (`mu`.`id_ue` = `ue`.`id_ue`)))) left join `t_element_constitutif` `ec` on((`ec`.`id_ue` = `ue`.`id_ue`))) left join `t_mention_ue_ec` `mec` on(((`mec`.`id_mention_ue` = `mu`.`id_mention_ue`) and (`mec`.`id_ec` = `ec`.`id_ec`)))) left join (select `c1`.`matricule` AS `matricule`,`c1`.`id_ec` AS `id_ec`,`c1`.`cote_s1` AS `cote_s1`,`c1`.`cote_s2` AS `cote_s2` from (`t_cote` `c1` join (select `t_cote`.`matricule` AS `matricule`,`t_cote`.`id_ec` AS `id_ec`,max(`t_cote`.`id_note`) AS `max_id_note` from `t_cote` where (`t_cote`.`id_ec` is not null) group by `t_cote`.`matricule`,`t_cote`.`id_ec`) `c2` on((`c1`.`id_note` = `c2`.`max_id_note`)))) `c_ec` on(((`c_ec`.`matricule` = `e`.`matricule`) and (`c_ec`.`id_ec` = `ec`.`id_ec`)))) left join (select `c1`.`matricule` AS `matricule`,`c1`.`id_ue` AS `id_ue`,`c1`.`cote_s1` AS `cote_s1`,`c1`.`cote_s2` AS `cote_s2` from (`t_cote` `c1` join (select `t_cote`.`matricule` AS `matricule`,`t_cote`.`id_ue` AS `id_ue`,max(`t_cote`.`id_note`) AS `max_id_note` from `t_cote` where (`t_cote`.`id_ue` is not null) group by `t_cote`.`matricule`,`t_cote`.`id_ue`) `c2` on((`c1`.`id_note` = `c2`.`max_id_note`)))) `c_ue` on(((`c_ue`.`matricule` = `e`.`matricule`) and (`c_ue`.`id_ue` = `ue`.`id_ue`))));

-- Structure de la table 'vue_programme_etudiant_complet'
DROP TABLE IF EXISTS `vue_programme_etudiant_complet`;
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vue_programme_etudiant_complet` AS select `e`.`matricule` AS `matricule`,`e`.`nom_etu` AS `nom_etu`,`e`.`postnom_etu` AS `postnom_etu`,`e`.`prenom_etu` AS `prenom_etu`,`m`.`id_mention` AS `id_mention`,`m`.`code_mention` AS `code_mention`,`m`.`libelle` AS `mention`,`f`.`idFiliere` AS `idFiliere`,`f`.`code_filiere` AS `code_filiere`,`f`.`nomFiliere` AS `nomFiliere`,`d`.`id_domaine` AS `id_domaine`,`d`.`code_domaine` AS `code_domaine`,`d`.`nom_domaine` AS `nom_domaine`,`p`.`code_promotion` AS `code_promotion`,`p`.`nom_promotion` AS `nom_promotion`,`a`.`id_annee` AS `id_annee`,`a`.`date_debut` AS `date_debut`,`a`.`date_fin` AS `date_fin`,`s`.`id_semestre` AS `id_semestre`,`s`.`code_semestre` AS `code_semestre`,`s`.`nom_semestre` AS `nom_semestre`,`ue`.`id_ue` AS `id_ue`,`ue`.`code_ue` AS `code_ue`,`ue`.`libelle` AS `unite_enseignement`,`ue`.`credits` AS `ue_credits`,`ue`.`heures_th` AS `ue_heures_th`,`ue`.`heures_td` AS `ue_heures_td`,`ue`.`heures_tp` AS `ue_heures_tp`,`ue`.`total_heures` AS `ue_total_heures`,`ec`.`id_ec` AS `id_ec`,`ec`.`code_ec` AS `code_ec`,`ec`.`libelle` AS `element_constitutif`,`ec`.`coefficient` AS `coefficient`,`ec`.`heures_th` AS `ec_heures_th`,`ec`.`heures_td` AS `ec_heures_td`,`ec`.`heures_tp` AS `ec_heures_tp`,`ec`.`total_heures` AS `ec_total_heures`,`c`.`cote_s1` AS `cote_s1`,`c`.`cote_s2` AS `cote_s2`,coalesce((`c`.`cote_s1` * `ec`.`coefficient`),0) AS `cote_s1_ponderee`,coalesce((`c`.`cote_s2` * `ec`.`coefficient`),0) AS `cote_s2_ponderee`,(case when ((`c`.`cote_s1` is null) and (`c`.`cote_s2` is null)) then 'Non évalué' when (((`c`.`cote_s1` + `c`.`cote_s2`) / 2) >= 10) then 'Admis' else 'Non admis' end) AS `decision` from ((((((((((((`t_etudiant` `e` join `t_inscription` `i` on((`i`.`matricule` = `e`.`matricule`))) join `t_promotion` `p` on((`p`.`code_promotion` = `i`.`code_promotion`))) join `t_anne_academique` `a` on((`a`.`id_annee` = `i`.`id_annee`))) join `t_mention` `m` on((`m`.`id_mention` = `i`.`id_mention`))) join `t_filiere` `f` on((`f`.`idFiliere` = `m`.`idFiliere`))) join `t_domaine` `d` on((`d`.`id_domaine` = `f`.`id_domaine`))) join `t_unite_enseignement` `ue` on((`ue`.`code_promotion` = `i`.`code_promotion`))) join `t_semestre` `s` on(((`s`.`id_semestre` = `ue`.`id_semestre`) and (`s`.`id_annee` = `a`.`id_annee`)))) left join `t_mention_ue` `mu` on(((`mu`.`id_mention` = `m`.`id_mention`) and (`mu`.`id_ue` = `ue`.`id_ue`)))) left join `t_element_constitutif` `ec` on((`ec`.`id_ue` = `ue`.`id_ue`))) left join `t_mention_ue_ec` `mec` on(((`mec`.`id_mention_ue` = `mu`.`id_mention_ue`) and (`mec`.`id_ec` = `ec`.`id_ec`)))) left join (select `c1`.`matricule` AS `matricule`,`c1`.`id_ec` AS `id_ec`,`c1`.`cote_s1` AS `cote_s1`,`c1`.`cote_s2` AS `cote_s2` from (`t_cote` `c1` join (select `t_cote`.`matricule` AS `matricule`,`t_cote`.`id_ec` AS `id_ec`,max(`t_cote`.`id_note`) AS `max_id_note` from `t_cote` group by `t_cote`.`matricule`,`t_cote`.`id_ec`) `c2` on((`c1`.`id_note` = `c2`.`max_id_note`)))) `c` on(((`c`.`matricule` = `e`.`matricule`) and (`c`.`id_ec` = `ec`.`id_ec`))));

-- Structure de la table 'vue_ue_ec_complete'
DROP TABLE IF EXISTS `vue_ue_ec_complete`;
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vue_ue_ec_complete` AS select `ue`.`id_ue` AS `id_ue`,`ue`.`code_ue` AS `code_ue`,`ue`.`libelle` AS `libelle_ue`,`ue`.`credits` AS `credits`,`ue`.`code_promotion` AS `code_promotion`,`ec`.`id_ec` AS `id_ec`,`ec`.`code_ec` AS `code_ec`,`ec`.`libelle` AS `libelle_ec`,`mu`.`id_mention` AS `id_mention`,`mu`.`semestre` AS `semestre`,`ec`.`coefficient` AS `coef_ec` from (((`t_unite_enseignement` `ue` join `t_mention_ue` `mu` on((`mu`.`id_ue` = `ue`.`id_ue`))) left join `t_element_constitutif` `ec` on((`ec`.`id_ue` = `ue`.`id_ue`))) left join `t_mention_ue_ec` `muec` on(((`muec`.`id_mention_ue` = `mu`.`id_mention_ue`) and (`muec`.`id_ec` = `ec`.`id_ec`))));

SET FOREIGN_KEY_CHECKS=1;
